public String plusOut(String str, String word)
{
    String returnString = "";
    int lastIndex = str.indexOf(word);
    int i = lastIndex;

    while (i < str.length())   
    {
        if (i == str.indexOf(word, lastIndex))
        {
            returnString = returnString + word;
            lastIndex = i;
            i += (word.length() - 1);
        }

        else
        {
            returnString = returnString + "+";
            i++;
        }
    }
	return returnString;
}

public boolean bobThere(String str)
{
